<script setup lang="ts">
import { computed, onMounted, reactive, ref } from 'vue'
import { ApiError, apiRequest, authState } from '../auth'
import AppShell from '../components/AppShell.vue'
import type { Customer, CustomerDetail, CustomerPage, FollowUp, Funnel, MergePreview, Opportunity, Stage, TimelineEvent } from '../crm'
import type { Employee, EmployeePage } from '../employee'

const customers = ref<Customer[]>([]); const employees = ref<Employee[]>([]); const stages = ref<Stage[]>([]); const funnel = ref<Funnel>({ items: [] })
const selected = ref<CustomerDetail | null>(null); const followUps = ref<FollowUp[]>([]); const timeline = ref<TimelineEvent[]>([]); const opportunities = ref<Opportunity[]>([])
const search = ref(''); const loading = ref(true); const errorMessage = ref(''); const message = ref(''); const showStages = ref(false); const mergeSourceId = ref(''); const mergePreview = ref<MergePreview | null>(null)
const canManageAll = computed(() => authState.user?.permissions.includes('customer.all_manage') ?? false)
const canManageOpportunity = computed(() => authState.user?.permissions.includes('opportunity.manage') ?? false)
const canManageStages = computed(() => authState.user?.permissions.includes('opportunity.stage.manage') ?? false)
const followForm = reactive({ method: 'phone', content: '', next_follow_up_at: '' })
const opportunityForm = reactive({ title: '', stage_id: '', expected_amount: 0, expected_close_date: '' })
const stageForm = reactive({ code: '', name: '', probability: 10, sort_order: 0, is_won: false, is_lost: false })
const employeeName = (id: string) => employees.value.find(item => item.id === id)?.name ?? '当前负责人'
const stageName = (id: string) => stages.value.find(item => item.id === id)?.name ?? '未知阶段'
async function load() { loading.value = true; try { const params = new URLSearchParams({ limit: '100' }); if (search.value) params.set('search', search.value); const requests: [Promise<CustomerPage>, Promise<Stage[]>, Promise<Funnel>, Promise<EmployeePage | null>] = [apiRequest(`/tenant/customers?${params}`), apiRequest('/tenant/opportunity-stages'), apiRequest('/tenant/opportunities/funnel/summary'), canManageAll.value ? apiRequest('/tenant/employees?limit=100') : Promise.resolve(null)]; const [page, stageValues, funnelValue, employeePage] = await Promise.all(requests); customers.value = page.items; stages.value = stageValues; funnel.value = funnelValue; employees.value = employeePage?.items ?? []; if (!opportunityForm.stage_id && stages.value.length) opportunityForm.stage_id = stages.value[0].id } catch (error) { errorMessage.value = error instanceof ApiError ? error.message : '客户数据加载失败' } finally { loading.value = false } }
async function openCustomer(customer: Customer) { try { const [detail, followValues, eventValues, opportunityValues] = await Promise.all([apiRequest<CustomerDetail>(`/tenant/customers/${customer.id}`), apiRequest<FollowUp[]>(`/tenant/customers/${customer.id}/follow-ups`), apiRequest<TimelineEvent[]>(`/tenant/customers/${customer.id}/timeline`), apiRequest<Opportunity[]>(`/tenant/customers/${customer.id}/opportunities`)]); selected.value = detail; followUps.value = followValues; timeline.value = eventValues; opportunities.value = opportunityValues; mergePreview.value = null; mergeSourceId.value = '' } catch (error) { errorMessage.value = error instanceof ApiError ? error.message : '客户详情加载失败' } }
async function addFollowUp() { if (!selected.value) return; try { await apiRequest(`/tenant/customers/${selected.value.id}/follow-ups`, { method: 'POST', body: JSON.stringify({ method: followForm.method, content: followForm.content, next_follow_up_at: followForm.next_follow_up_at || null }) }); Object.assign(followForm, { method: 'phone', content: '', next_follow_up_at: '' }); await openCustomer(selected.value); message.value = '跟进记录已保存' } catch (error) { errorMessage.value = error instanceof ApiError ? error.message : '跟进保存失败' } }
async function addOpportunity() { if (!selected.value) return; try { await apiRequest(`/tenant/customers/${selected.value.id}/opportunities`, { method: 'POST', body: JSON.stringify({ ...opportunityForm, expected_close_date: opportunityForm.expected_close_date || null }) }); Object.assign(opportunityForm, { title: '', stage_id: stages.value[0]?.id ?? '', expected_amount: 0, expected_close_date: '' }); await openCustomer(selected.value); await load(); message.value = '商机已创建' } catch (error) { errorMessage.value = error instanceof ApiError ? error.message : '商机创建失败' } }
async function changeStage(opportunity: Opportunity, stageId: string) { await apiRequest(`/tenant/opportunities/${opportunity.id}`, { method: 'PATCH', body: JSON.stringify({ stage_id: stageId }) }); if (selected.value) await openCustomer(selected.value); await load() }
async function transfer(employeeId: string) { if (!selected.value) return; selected.value = await apiRequest(`/tenant/customers/${selected.value.id}/transfer`, { method: 'POST', body: JSON.stringify({ employee_id: employeeId }) }); await load() }
async function archive() { if (!selected.value || !confirm('确认归档该客户？')) return; await apiRequest(`/tenant/customers/${selected.value.id}/archive`, { method: 'POST' }); selected.value = null; await load() }
async function previewMerge() { if (!selected.value || !mergeSourceId.value) return; mergePreview.value = await apiRequest(`/tenant/customers/${selected.value.id}/merge-preview`, { method: 'POST', body: JSON.stringify({ source_customer_id: mergeSourceId.value }) }) }
async function merge() { if (!selected.value || !mergeSourceId.value || !confirm('合并后来源客户将不可单独访问，确认继续？')) return; await apiRequest(`/tenant/customers/${selected.value.id}/merge`, { method: 'POST', body: JSON.stringify({ source_customer_id: mergeSourceId.value }) }); await openCustomer(selected.value); await load(); message.value = '客户已合并，联系人、跟进、商机和时间线均已迁移' }
async function createStage() { await apiRequest('/tenant/opportunity-stages', { method: 'POST', body: JSON.stringify(stageForm) }); Object.assign(stageForm, { code: '', name: '', probability: 10, sort_order: 0, is_won: false, is_lost: false }); await load() }
async function updateStage(stage: Stage) { await apiRequest(`/tenant/opportunity-stages/${stage.id}`, { method: 'PATCH', body: JSON.stringify({ name: stage.name, probability: stage.probability, sort_order: stage.sort_order, is_active: stage.is_active }) }); await load() }
onMounted(load)
</script>

<template><AppShell><header class="page-header compact"><div><p class="eyebrow">CUSTOMER CRM</p><h1>客户档案与商机</h1><p>从线索转化、持续跟进到商机推进的统一客户视图。</p></div><button v-if="canManageStages" class="secondary-button" @click="showStages = true">配置商机阶段</button></header><div v-if="message" class="notice success">{{ message }}</div><div v-if="errorMessage" class="notice error">{{ errorMessage }}</div><section class="funnel-grid"><article v-for="item in funnel.items" :key="item.stage_id" class="panel"><span>{{ item.stage_name }}</span><b>{{ item.count }}</b><small>¥ {{ Number(item.expected_amount).toLocaleString() }}</small></article></section><section class="panel employee-filters"><input v-model.trim="search" placeholder="搜索客户或联系方式" @keyup.enter="load" /><button class="secondary-button" @click="load">查询</button></section><section class="panel table-panel"><div v-if="loading" class="empty-state">正在加载客户…</div><div v-else-if="!customers.length" class="empty-state">暂无客户，可在线索中心将线索转为客户</div><table v-else><thead><tr><th>客户</th><th>标签</th><th>负责人</th><th>状态</th><th>更新时间</th></tr></thead><tbody><tr v-for="customer in customers" :key="customer.id" class="clickable-row" @click="openCustomer(customer)"><td><b>{{ customer.name }}</b><small>{{ customer.primary_contact }}</small></td><td><span v-for="tag in customer.tags" :key="tag" class="tag">{{ tag }}</span></td><td>{{ employeeName(customer.owner_employee_id) }}</td><td>{{ customer.status === 'active' ? '正常' : '已归档' }}</td><td>{{ new Date(customer.updated_at).toLocaleString() }}</td></tr></tbody></table></section><div v-if="selected" class="modal-backdrop crm-backdrop" @click.self="selected = null"><article class="modal crm-detail"><button class="modal-close" @click="selected = null">×</button><p class="eyebrow">CUSTOMER 360</p><h2>{{ selected.name }}</h2><p>{{ selected.primary_contact }} · {{ employeeName(selected.owner_employee_id) }}</p><div class="crm-columns"><section><h3>联系人</h3><article v-for="contact in selected.contacts" :key="contact.id" class="crm-item"><b>{{ contact.name }}</b><small>{{ contact.contact_type }} · {{ contact.contact_value }}</small></article><form @submit.prevent="addFollowUp"><h3>新增跟进</h3><select v-model="followForm.method"><option value="phone">电话</option><option value="wechat">微信</option><option value="email">邮件</option><option value="meeting">面谈</option><option value="other">其他</option></select><textarea v-model.trim="followForm.content" required rows="3" placeholder="跟进内容" /><label><span>下次提醒</span><input v-model="followForm.next_follow_up_at" type="datetime-local" /></label><button class="primary-button">保存跟进</button></form><h3>跟进记录</h3><article v-for="item in followUps" :key="item.id" class="crm-item"><b>{{ item.method }} · {{ new Date(item.occurred_at).toLocaleString() }}</b><p>{{ item.content }}</p><small v-if="item.next_follow_up_at">下次：{{ new Date(item.next_follow_up_at).toLocaleString() }}</small></article></section><section><form v-if="canManageOpportunity" @submit.prevent="addOpportunity"><h3>新建商机</h3><input v-model.trim="opportunityForm.title" required placeholder="商机名称" /><div class="form-columns"><select v-model="opportunityForm.stage_id"><option v-for="stage in stages.filter(item => item.is_active)" :key="stage.id" :value="stage.id">{{ stage.name }}</option></select><input v-model.number="opportunityForm.expected_amount" type="number" min="0" step="0.01" placeholder="预计金额" /><input v-model="opportunityForm.expected_close_date" type="date" /></div><button class="primary-button">创建商机</button></form><h3>商机</h3><article v-for="opportunity in opportunities" :key="opportunity.id" class="crm-item"><b>{{ opportunity.title }}</b><p>¥ {{ Number(opportunity.expected_amount).toLocaleString() }} · {{ opportunity.expected_close_date || '未定成交时间' }}</p><select :value="opportunity.stage_id" @change="changeStage(opportunity, ($event.target as HTMLSelectElement).value)"><option v-for="stage in stages.filter(item => item.is_active)" :key="stage.id" :value="stage.id">{{ stage.name }}</option></select></article><h3>客户时间线</h3><article v-for="event in timeline" :key="event.id" class="timeline-item"><i></i><div><b>{{ event.title }}</b><small>{{ new Date(event.occurred_at).toLocaleString() }}</small><p v-if="event.details.source">来源：{{ event.details.source }}</p></div></article><template v-if="canManageAll"><h3>管理操作</h3><label><span>转移负责人</span><select :value="selected.owner_employee_id" @change="transfer(($event.target as HTMLSelectElement).value)"><option v-for="employee in employees.filter(item => item.status === 'active')" :key="employee.id" :value="employee.id">{{ employee.name }}</option></select></label><label><span>合并其他客户</span><select v-model="mergeSourceId"><option value="">请选择来源客户</option><option v-for="customer in customers.filter(item => item.id !== selected?.id)" :key="customer.id" :value="customer.id">{{ customer.name }} · {{ customer.primary_contact }}</option></select></label><button class="secondary-button" @click="previewMerge">预览冲突</button><div v-if="mergePreview" class="merge-preview"><b>冲突字段</b><p v-for="(values, field) in mergePreview.conflicts" :key="field">{{ field }}：{{ values.join(' / ') }}</p><p>将迁移：联系人 {{ mergePreview.moved_counts.contacts }}、跟进 {{ mergePreview.moved_counts.follow_ups }}、商机 {{ mergePreview.moved_counts.opportunities }}</p><button class="primary-button" @click="merge">确认合并</button></div><button class="link-button danger" @click="archive">归档客户</button></template></section></div></article></div><div v-if="showStages" class="modal-backdrop" @click.self="showStages = false"><article class="modal stage-modal"><button class="modal-close" @click="showStages = false">×</button><p class="eyebrow">PIPELINE STAGES</p><h2>商机阶段配置</h2><article v-for="stage in stages" :key="stage.id" class="stage-row"><input v-model="stage.name" /><input v-model.number="stage.probability" type="number" min="0" max="100" /><input v-model.number="stage.sort_order" type="number" min="0" /><label><input v-model="stage.is_active" type="checkbox" />启用</label><button class="link-button" @click="updateStage(stage)">保存</button></article><form class="stage-row" @submit.prevent="createStage"><input v-model.trim="stageForm.code" required placeholder="编号" /><input v-model.trim="stageForm.name" required placeholder="名称" /><input v-model.number="stageForm.probability" type="number" min="0" max="100" /><input v-model.number="stageForm.sort_order" type="number" min="0" /><button class="primary-button">新增</button></form></article></div></AppShell></template>
